import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.ePeAWSvT.js";const s="/assets/monitor-dashboard.dfXP_f8a.png",i="/assets/monitor-dashboard-table-view.rMixBtS6.png",m=JSON.parse('{"title":"Monitor Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/monitor-dashboard.md","filePath":"guide/monitor-dashboard.md"}'),n={name:"guide/monitor-dashboard.md"};function d(h,t,l,g,c,p){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="monitor-dashboard" tabindex="-1">Monitor Dashboard <a class="header-anchor" href="#monitor-dashboard" aria-label="Permalink to &quot;Monitor Dashboard&quot;">​</a></h1><p>The Monitor Dashboard provides an at-a-glance view of your integration platform&#39;s health and activity. View message processing metrics, trends over time, and publisher endpoint statuses.</p><p><img src="'+s+'" alt="Monitor Dashboard"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Message Metrics</strong> — View total published, processed, successful, and errored messages by endpoint</li><li><strong>Time-Based Charts</strong> — Track processing trends over the last hour, day, week, or month</li><li><strong>Publisher Status</strong> — Monitor the health and last run time of each publisher endpoint</li></ul><h2 id="view-the-dashboard" tabindex="-1">View the Dashboard <a class="header-anchor" href="#view-the-dashboard" aria-label="Permalink to &quot;View the Dashboard&quot;">​</a></h2><ol><li>Select <strong>Monitor</strong> &gt; <strong>Dashboard</strong> from the main menu.</li><li>Then, use the table below to determine the next steps.</li></ol><table tabindex="0"><thead><tr><th>To</th><th>Do this</th></tr></thead><tbody><tr><td><strong>View data in graph format</strong></td><td>Select the <strong>graph</strong> icon.</td></tr><tr><td><strong>View data in table format</strong></td><td>Select the <strong>table</strong> icon.</td></tr><tr><td><strong>Reload</strong></td><td>Select <strong>Reload</strong> to refresh the data.</td></tr><tr><td><strong>Set a specific date range</strong></td><td>Select <strong>Set Range</strong>. Select a pre-formulated <strong>timeframe</strong> (e.g. Last Hour) or select <strong>Custom</strong> to apply a specific date and time. Select <strong>Apply</strong>. By default, the system will show data for the <strong>Last Day</strong>.</td></tr></tbody></table><h3 id="graph-view-dashboard" tabindex="-1">Graph View Dashboard <a class="header-anchor" href="#graph-view-dashboard" aria-label="Permalink to &quot;Graph View Dashboard&quot;">​</a></h3><p>The Graph View provides a visual depiction of system activity across your Data Hubs.</p><table tabindex="0"><thead><tr><th>Section</th><th>Description</th></tr></thead><tbody><tr><td><strong>Monitoring Dashboard</strong></td><td>Visual depiction of the systems&#39; errors and published messages for the given date range.</td></tr><tr><td><strong>Total Messages</strong></td><td>A quantified depiction of the total published and successful messages, as well as errors.</td></tr><tr><td><strong>Publisher Health</strong></td><td>Easily visible indication of each system&#39;s health at the Endpoint level. Select any <strong>system</strong> to view the Messages for that Endpoint.</td></tr></tbody></table><h3 id="table-view-dashboard" tabindex="-1">Table View Dashboard <a class="header-anchor" href="#table-view-dashboard" aria-label="Permalink to &quot;Table View Dashboard&quot;">​</a></h3><p>The Table View provides a granular, tabular breakdown of message activity per endpoint.</p><p><img src="'+i+'" alt="Monitor Dashboard Table View"></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Select the <strong>filter</strong> icon or <strong>sort</strong> arrow in any column header to narrow your search. The filters will vary based on that column&#39;s data. You can apply filters to one or multiple columns.</p><p>Select the <strong>graph</strong> icon in the final column of any row to view that specific Endpoint&#39;s data in a visual format.</p></div><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Endpoint Name</strong></td><td>The data is being published to this Data Hub Endpoint, which you established when creating the Data Hub.</td></tr><tr><td><strong>Transaction Type</strong></td><td>Describes the logical grouping of the type of data event being transcribed, e.g. Save Employee Data, Save Invoice. This is the trigger point for data publishing, while the Entity Type refers to the type of data that it&#39;s tied to on the Common Model.</td></tr><tr><td><strong>System Name</strong></td><td>The Connector system publishing that data within that Data Hub Endpoint.</td></tr><tr><td><strong>Entity Type</strong></td><td>The type of data represented in the payload of the message, referencing the type of data that it&#39;s tied to on the Common Model. This field directly ties back to the Schema Definition.</td></tr><tr><td><strong>Published</strong></td><td>The number of data messages published within the set date range.</td></tr><tr><td><strong>Processed</strong></td><td>The number of data messages processed within the set date range.</td></tr><tr><td><strong>Errors</strong></td><td>The number of error messages that occurred within the set date range.</td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./monitor-messages.html">Messages</a> — Inspect individual integration messages</li><li><a href="./monitor-error-logs.html">Error Logs</a> — Investigate processing errors</li><li><a href="./monitor-publisher-logs.html">Publisher Logs</a> — Review publisher run history</li><li><a href="./monitor-alerts.html">Alerts</a> — Configure automated error notifications</li></ul>',18)])])}const u=e(n,[["render",d]]);export{m as __pageData,u as default};
